class Solution:
    def largestRectangleArea(self, heights: List[int]) -> int:
        st = []; ans = 0
        for i, h in enumerate(heights + [0]):
            while st and heights[st[-1]] > h:
                H = heights[st.pop()]
                w = i if not st else i - st[-1] - 1
                ans = max(ans, H * w)
            st.append(i)
        return ans

