class Solution {
public:
    int largestRectangleArea(vector<int>& h) {
        stack<int> st; int ans=0; h.push_back(0);
        for (int i=0;i<(int)h.size();i++) {
            while (!st.empty() && h[st.top()]>h[i]) {
                int H=h[st.top()]; st.pop();
                int w = st.empty()? i : i-st.top()-1;
                ans=max(ans, H*w);
            }
            st.push(i);
        }
        h.pop_back(); return ans;
    }
};
